onClick:
{{
(() => {

  return GetUserLogin.run()

    .then(() => {

      const user = GetUserLogin.data?.[0];

      if (!user) {
        showAlert("Invalid login", "error");
        return;
      }

      // 🔹 store basic user first
      return storeValue("userContext", {
        id: user.id,
        name: user.Name,
        email: user.Email
      })

      // 🔥 load full context (departments + approver etc)
      .then(() => UserContext.loadUserContext())

      .then(() => {
        navigateTo("Home");
      });

    })

    .catch((err) => {
      console.error("Login failed:", err);
      showAlert("Login error", "error");
    });

})()
}}
